# List all Azure identities with HIGH PCI (score >= 67) — prioritise for right-sizing
$azureSysId = '<azure-authorization-system-id>'

# Query users with high PCI
$highRiskUsers = Invoke-MgGraphRequest -Method GET `
  -Uri "https://graph.microsoft.com/beta/external/authorizationSystems/$azureSysId/microsoft.graph.azureAuthorizationSystem/associatedIdentities/users?`$filter=permissionsCreepIndex/score ge 67&`$select=displayName,userPrincipalName,permissionsCreepIndex,lastActiveDateTime" |
  Select-Object -ExpandProperty value

$highRiskUsers | ForEach-Object {
    [PSCustomObject]@{
        DisplayName   = $_.displayName
        UPN           = $_.userPrincipalName
        PCIScore      = $_.permissionsCreepIndex.score
        LastActive    = $_.lastActiveDateTime
        DaysSinceUse  = if ($_.lastActiveDateTime) { ((Get-Date) - [datetime]$_.lastActiveDateTime).Days } else { 'Never' }
    }
} | Sort-Object PCIScore -Descending | Format-Table -AutoSize
